--- 主城路径上的对象
---@class LCityPathObj
local LCityPathObj = classX("LCityPathObj",nil)

LCityPathObj.Normal = 0
LCityPathObj.Birth = 1
LCityPathObj.Run = 2
LCityPathObj.Idle = 3

--- 测试数据
local dpList = {
    "XR_Lvniang01", "XR_Maniang01", "XR_Meiguiniang01",
    "XR_Munaiyi01", "XR_Nainiu01",
}

local aniNames = {
    [LCityPathObj.Birth] = "resurrected",
    [LCityPathObj.Run] = "run",
    [LCityPathObj.Idle] = "idle",
}

function LCityPathObj:ctor()
    ---@type LxSpineDp
    self._spObj = nil

    ---@type Transform
    self._parent = nil

    self._state = LCityPathObj.Normal

    self._time = nil

    ---@type LxTimer
    self._timer = nil

    ---@type table<Transform>
    self._pathPoints = {}

    self._speed = 1

    self._pointIdx = 1

    ---@type LxSequenceCom
    self._seqCom = nil
end

function LCityPathObj:Dispose()
    if self._spObj then
        self._spObj:Dispose()
        self._spObj = nil
    end

    if self._timer then
        MgrCenter.TimerMgr:RemoveTimer(self._timer)
        self._timer = nil
    end

    if self._seqCom then
        self._seqCom:Dispose()
        self._seqCom = nil
    end

    table.dispose(self)

    self._isDisposed = true
end

function LCityPathObj:IsDisposed()
    return self._isDisposed
end

function LCityPathObj:SetParent(parent)
    self._parent = parent
end

---@param pathPoints table<Transform>
function LCityPathObj:SetPathPoints(pathPoints)
    self._pathPoints = pathPoints
end

function LCityPathObj:SetPointIdx(pointIdx)
    self._pointIdx = pointIdx
end

function LCityPathObj:TestData()
    self:CreateSeqCom()
    local randomIdx = math.random(1,#dpList)
    self:InitSpData(dpList[randomIdx])
end

function LCityPathObj:CreateSeqCom()
    self._seqCom = require("LApp.component.tween.LxSequenceCom"):new()
end

function LCityPathObj:InitSpData(spineName)
    local spObj = require("LApp.component.dp.LxSpineDp"):new()
    self._spObj = spObj
    spObj:InitDp(spineName,self._parent)
    spObj:SetFormationState(true)
    spObj:SetLocalPosition(Vector3.zero)
    spObj:SetScale(1)
    spObj:SetLoadedCallback(function(dpSpine)
        self:_DoSpBirth(dpSpine)
    end)
    spObj:OnAniamationComplete(function(aniName)
        self:AniamationComplete(aniName)
    end)
    spObj:Load()
end

function LCityPathObj:AniamationComplete(aniName)
    if aniName == "idle" then
    elseif aniName == "resurrected" then
        self:_DoSpIdle()
    elseif aniName == "run" then
    end
end

---@param dpSpine LxSpineDp
function LCityPathObj:_DoSpBirth(dpSpine)
    if not dpSpine or not dpSpine:IsDpValid() then return end

    self._state = LCityPathObj.Birth
    self:PlaySpAni(aniNames[self._state],false)

    self._time = Time.time

    self:StartTimer()
end

function LCityPathObj:_DoSpIdle()
    local randomTime = math.random(1,4)
    self._time = Time.time + randomTime
    self._state = LCityPathObj.Idle
    self:PlaySpAni(aniNames[self._state],true)
end

function LCityPathObj:PlaySpAni(aniName,isLoop)
    if not self._spObj or not self._spObj:IsDpValid() then return end
    self._spObj:PlayAnimationInfo(aniName,isLoop,false,function(name)
        self:AniamationComplete(name)
    end)
end

function LCityPathObj:StartTimer()
    self._timer = MgrCenter.TimerMgr:NewTimeTimer(function()
        self:OnUpdate()
    end,self,1,-1)
end

function LCityPathObj:OnUpdate()
    if Time.time - self._time > 0 then
        if self._state == LCityPathObj.Birth then
        elseif self._state == LCityPathObj.Idle then
            self:OnPathObjRun()
        elseif self._state == LCityPathObj.Run then
        end
    end
end

function LCityPathObj:OnPathObjRun()
    local pointIdx = self._pointIdx
    local points = {}
    for i,v in ipairs(self._pathPoints) do
        table.insert(points,v)
    end
    local len = #points
    local randomIdx = math.random(1,len)
    if randomIdx == pointIdx then return end

    local endIdx
    local str = {}
    local pointTransList = {}
    if pointIdx < randomIdx then
        for i = pointIdx,randomIdx do
            if i ~= pointIdx then
                table.insert(str,tostring(i))
                table.insert(pointTransList,points[i])
                endIdx = i
            end
        end
    else
        for i = pointIdx,randomIdx,-1 do
            if i ~= pointIdx then
                table.insert(str,tostring(i))
                table.insert(pointTransList,points[i])
                endIdx = i
            end
        end
    end
    --print(table.concat(str,","))
    if #pointTransList < 1 then return end

    local parent = self._parent
    local tween = self._seqCom:CreateSeq("runTween")
    tween:AppendCallback(function()
        self._state = LCityPathObj.Run
        self:PlaySpAni(aniNames[self._state],true)
    end)

    local curPos
    local time = 0
    local spObj = self._spObj
    for i,v in ipairs(pointTransList) do
        if curPos then
            curPos = pointTransList[i - 1].position
        else
            curPos = parent.position
        end
        local dis1 = (curPos - v.position).magnitude
        local speed = dis1 / self._speed
        tween:InsertCallback(time,function()
            local bFilp = parent.position.x > v.position.x
            spObj:SetFlipX(bFilp)
        end)
        tween:Insert(time,parent:DOMove(v.position,speed):SetEase(TweenEase.Linear))
        time = time + speed
    end
    tween:OnComplete(function()
        if self:IsDisposed() then return end
        self._pointIdx = endIdx
        self._seqCom:DeleteSeq("runTween")
        self:_DoSpIdle()
    end)
    tween:PlayForward()

end

return LCityPathObj